import React, { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  CatalogTableSkeleton,
  CatalogListShell,
  ErpDataListGrid,
  ErpListHeaderFilters,
  LinListFilterField,
  loadErpListTableConfig,
  saveErpListTableConfig,
  LinListTableConfigModal,
  type ErpListTableConfig,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { useVoucherInitData } from '../../hooks/useVoucherInitData';
import { useVoucherListSelection } from '../../hooks/useVoucherListSelection';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { ktService } from '../../services/kt/ktService';
import type { JournalEntryDto } from '../../services/kt/models';
import { JOURNAL_ENTRY_PHIEU_DIEU_CHINH_CONFIG, type JournalEntryPageConfig } from '../../constants/journalEntryPageConfig';
import { formatDateLocal } from '../../utils/formatters';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import { formatProcessingLevelFromOptions } from '../../utils/voucherProcessingLevelOptions';
import { canEditFromListRow, canViewLedgerFromListRow } from '../../utils/voucherListRowActions';
import erp from '../../styles/erpPage.module.css';
import {
  DEFAULT_VOUCHER_LIST_PAGE_SIZE,
  VoucherListPagination,
  type VoucherListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';
import { ProcessingLevelApproveModal } from '../voucher/ProcessingLevelApproveModal';
import { VoucherPrintModal, VoucherPostedLedgerModal } from '../voucher';
import { VoucherListToolbar } from '../voucher-list';

const PAGE_SIZE = DEFAULT_VOUCHER_LIST_PAGE_SIZE;

function isRowSelectable(row: JournalEntryDto): boolean {
  return row.status === 'Draft';
}

export interface JournalEntryListProps {
  config?: JournalEntryPageConfig;
}

export const JournalEntryList: React.FC<JournalEntryListProps> = ({
  config = JOURNAL_ENTRY_PHIEU_DIEU_CHINH_CONFIG,
}) => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();

  const { processingLevelOptions, defaultProcessingLevel } = useVoucherInitData(config.initDataListFormName);
  const { canCreate, canApprove, canUpdate, canPrint, canViewLedger: canViewLedgerPerm } =
    useVoucherListActions(config.initDataCreateFormName);

  const processingFilterOptions = useMemo(
    () => [{ value: '', label: 'Tất cả mức xử lý' }, ...processingLevelOptions],
    [processingLevelOptions],
  );

  const formatProcessingLabel = (level: string | undefined) =>
    formatProcessingLevelFromOptions(level, processingLevelOptions);

  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    processingLevel,
    setProcessingLevel,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(config.listFilterScope);

  const [items, setItems] = useState<JournalEntryDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<VoucherListPageSize>(PAGE_SIZE);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showConfigModal, setShowConfigModal] = useState(false);

  const testId = config.testIdPrefix;
  const [tableConfig, setTableConfig] = useState<ErpListTableConfig>(() =>
    loadErpListTableConfig(testId),
  );
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const selection = useVoucherListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable,
  });

  const activeRow = selection.activeRow;

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow ? canEditFromListRow(activeRow, canUpdate) : false;
  const canViewLedgerActive = activeRow ? canViewLedgerFromListRow(activeRow, canViewLedgerPerm) : false;
  const canPrintActive = Boolean(activeRow) && canPrint;

  const refresh = () => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };

  const setPageSize = (size: number) => {
    setPageSizeState(size as VoucherListPageSize);
    resetPage();
    selection.clearSelection();
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      ktService.getJournalEntries({
        fromDate,
        toDate,
        search: search || undefined,
        processingLevel: processingLevel || undefined,
        entryKind: config.entryKind,
        page,
        pageSize,
      })
        .then(res => { if (!cancelled) { setItems(res.items); setTotalCount(res.totalCount); } })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải danh sách'), type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [fromDate, toDate, search, processingLevel, page, pageSize, reloadKey, dispatch, config.entryKind, initialized]);

  const handleBatchApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      await ktService.batchUpdateJournalEntryProcessingLevel({
        ids: selection.selectedIdList,
        processingLevel: newLevel,
      });
      dispatchAppToast(dispatch, { message: 'Phê duyệt thành công', type: 'success' });
      setShowApproveModal(false);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Phê duyệt thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  const navigateToRow = (id: string, startInEditMode?: boolean) => {
    navigate(config.detailPath(id), {
      state: startInEditMode ? { startInEditMode: true } : undefined,
    });
  };

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const handleSaveTableConfig = (next: ErpListTableConfig) => {
    setTableConfig(next);
    saveErpListTableConfig(testId, next);
  };

  const filters = (
    <ErpListHeaderFilters testIdPrefix={testId} filterCols={3} filterMaxWidthPx={1000}>
      <LinListFilterField testId={`${testId}-field-search`}>
        <SearchTextInput
          label="Tìm kiếm"
          placeholder="Tìm số phiếu, diễn giải..."
          value={searchDraft}
          onChange={setSearchDraft}
          onSearch={handleSearch}
          testId={`${testId}-search-text`}
        />
      </LinListFilterField>
      <LinListFilterField testId={`${testId}-field-dateRange`}>
        <DateRangeFilter
          label="Thời gian"
          fullWidth
          testId={`${testId}-date-range`}
          fromDate={fromDate}
          toDate={toDate}
          preset={datePreset}
          onChange={(v: DateRangeValue) => {
            applyDateRange(v.fromDate, v.toDate, v.preset);
            resetPage();
          }}
        />
      </LinListFilterField>
      <LinListFilterField testId={`${testId}-field-processingLevel`}>
        <Select
          label="Mức xử lý"
          value={processingLevel}
          onChange={e => { setProcessingLevel(e.target.value); resetPage(); }}
          options={processingFilterOptions}
          fullWidth
          data-testid={`${testId}-filter-processing-level`}
        />
      </LinListFilterField>
    </ErpListHeaderFilters>
  );

  return (
    <div
      className={`${erp.page} ${erp.catalogListPage} ${erp.voucherListPage}`}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${testId}-list`}
    >
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}>
          <h1 className={erp.title} data-testid={`${testId}-title`}>
            <i className={`fas ${config.listIcon}`} /> {config.listTitle}
          </h1>
        </div>
      </div>

      <VoucherListToolbar
        testIdPrefix={testId}
        onRefresh={refresh}
        canApprove={canApprove}
        approveDisabled={selection.selectedCount === 0}
        onApprove={() => setShowApproveModal(true)}
        canViewLedger={canViewLedgerActive}
        onViewLedger={() => setShowLedgerModal(true)}
        canPrint={canPrintActive}
        onPrint={() => setShowPrintModal(true)}
        canView={canViewActive}
        onView={() => activeRow && navigateToRow(activeRow.id)}
        canEdit={canEditActive}
        onEdit={() => activeRow && navigateToRow(activeRow.id, true)}
        canCreate={canCreate}
        onCreate={() => navigate(config.createPath)}
        onEditConfig={() => setShowConfigModal(true)}
      />

      {selection.selectedCount > 0 && (
        <div className={erp.batchBar} data-testid={`${testId}-batch-bar`}>
          <span>Đã chọn {selection.selectedCount}</span>
          <button
            type="button"
            className={erp.batchBarLink}
            data-testid={`${testId}-batch-clear`}
            onClick={selection.clearSelection}
          >
            Bỏ chọn tất cả
          </button>
        </div>
      )}

      <CatalogListShell
        testIdPrefix={testId}
        title={`Danh sách ${config.listTitle.toLowerCase()}`}
        showTableLoading={showTableLoading}
        filters={filters}
        footer={!showTableLoading && (
          <VoucherListPagination
            testIdPrefix={testId}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        )}
      >
        {showTableLoading ? (
          <CatalogTableSkeleton
            rows={Math.min(pageSize, 8)}
            data-testid={`${testId}-table-skeleton`}
          />
        ) : items.length === 0 ? (
          <div className={erp.empty}>Không có dữ liệu</div>
        ) : (
          <ErpDataListGrid
            testIdPrefix={testId}
            rows={items}
            page={page}
            pageSize={pageSize}
            selection={selection}
            isRowSelectable={isRowSelectable}
            getRowId={r => r.id}
            tableConfig={{ ...tableConfig, resizable: false }}
            onRowDoubleClick={row => navigateToRow(row.id)}
            headerCells={(
              <>
                <th>Số CT</th>
                <th>Ngày</th>
                <th>Diễn giải</th>
                <th>Mức xử lý</th>
              </>
            )}
            renderRow={r => (
              <>
                <td>
                  <code>{r.code}</code>
                </td>
                <td>{formatDateLocal(r.entryDate)}</td>
                <td>{r.description}</td>
                <td data-testid={`${testId}-row-${r.id}-processing-level`}>
                  {formatProcessingLabel(r.processingLevel)}
                </td>
              </>
            )}
          />
        )}
      </CatalogListShell>

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={defaultProcessingLevel ?? ''}
        levelOptions={processingLevelOptions}
        onConfirm={handleBatchApproveConfirm}
        saving={approving}
        testIdPrefix={testId}
      />

      {activeRow && (
        <>
          <VoucherPrintModal
            isOpen={showPrintModal}
            onClose={() => setShowPrintModal(false)}
            voucherTitle={`${config.listTitle} — ${activeRow.code}`}
            onPrint={handlePrintConfirm}
            printing={printing}
            testIdPrefix={testId}
          />
          <VoucherPostedLedgerModal
            isOpen={showLedgerModal}
            onClose={() => setShowLedgerModal(false)}
            voucherTitle={`${config.listTitle} — ${activeRow.code}`}
            testIdPrefix={testId}
            fetchPostedLedger={() => ktService.getJournalEntryPostedLedger(activeRow.id)}
            fetchPostingStatus={() => ktService.getJournalEntryPostingStatus(activeRow.id)}
          />
        </>
      )}

      <LinListTableConfigModal
        isOpen={showConfigModal}
        onClose={() => setShowConfigModal(false)}
        testIdPrefix={testId}
        config={tableConfig}
        onSave={handleSaveTableConfig}
      />
    </div>
  );
};
